// src/pages/CreateExperience.js
import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { experiencesService } from '../services/experiences';
import { coursesService } from '../services/courses';
import { authService } from '../services/auth';

export default function CreateExperience() {
  const navigate = useNavigate();
  const [myCourses, setMyCourses] = useState([]);
  const [loading, setLoading] = useState(false);
  const [fetchingCourses, setFetchingCourses] = useState(true);

  // حماية الصفحة: لو مش مدرس يرجع لصفحة التجارب
  const user = authService.getUserFromStorage();

// 1. شيل الـ user من الـ Dependency Array لو هو بيجي من الـ Storage مرة واحدة
  useEffect(() => {
    const currentUser = authService.getUserFromStorage();
    if (!currentUser?.is_instructor) {
      navigate('/experiences');
      return;
    }
    loadInstructorCourses();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // خليه يشتغل مرة واحدة فقط عند تحميل الصفحة

  const [form, setForm] = useState({
    section: '',
    title: '',
    description: '',
    price: '0',
    discount_price: '',
    instructor_cut: '70',
    college_cut: '30',
    preview_video_url: '',
    status: 'draft',
  });

  const [imageFile, setImageFile] = useState(null);
  const [errors, setErrors] = useState({});

  // جلب الكورسات الخاصة بالمدرس فقط
  const loadInstructorCourses = async () => {
    try {
      setFetchingCourses(true);
      // ملاحظة: يفضل استخدام endpoint في الباك اند يرجع كورسات المدرس الحالي فقط
      // مثل: /api/courses/my-courses/
      const data = await coursesService.getAll(); 
      const list = data.results ?? data;

      // فلترة الكورسات لضمان أنها تخص المدرس الحالي فقط (أمان إضافي في الفرونت)
      const instructorOwned = list.filter(c => c.instructor === user?.id || c.instructor_email === user?.email);
      setMyCourses(instructorOwned);
    } catch (err) {
      console.error("Error fetching courses:", err);
    } finally {
      setFetchingCourses(false);
    }
  };

  const handle = (e) => {
    const { name, value, files } = e.target;
    if (name === 'image') {
      setImageFile(files[0]);
    } else {
      setForm(f => ({ ...f, [name]: value }));
      if (name === 'instructor_cut') {
        const ic = parseFloat(value) || 0;
        const cappedIc = Math.min(100, Math.max(0, ic));
        setForm(f => ({ 
          ...f, 
          instructor_cut: String(cappedIc), 
          college_cut: String(100 - cappedIc) 
        }));
      }
    }
  };

  const validate = () => {
    const e = {};
    if (!form.title) e.title = 'أدخل عنوان التجربة';
    if (parseFloat(form.price) < 0) e.price = 'السعر لا يمكن أن يكون سالباً';
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const submit = async (e, publishNow = false) => {
    e.preventDefault();
    if (!validate()) return;
    setLoading(true);

    try {
      const formData = new FormData();
      // إذا اختار سكشن نرسل الـ ID، وإذا لم يختر تظل تجربة عامة
      if (form.section) formData.append('section', form.section);

      formData.append('title', form.title);
      formData.append('content', form.description);
      formData.append('price', form.price);
      formData.append('instructor_cut', form.instructor_cut);
      formData.append('college_cut', form.college_cut);
      formData.append('status', publishNow ? 'published' : 'draft');

      if (form.discount_price) formData.append('discount_price', form.discount_price);
      if (form.preview_video_url) formData.append('preview_video_url', form.preview_video_url);
      if (imageFile) formData.append('image', imageFile);

      await experiencesService.create(formData);
      alert(publishNow ? '✅ تم النشر بنجاح!' : '✅ تم الحفظ كمسودة');
      navigate('/experiences');
    } catch (err) {
      const data = err.response?.data;
      if (data && typeof data === 'object') setErrors(data);
      else alert('حدث خطأ أثناء الحفظ');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={s.page}>
      <div style={s.container}>
        <h1 style={s.title}>إنشاء تجربة جديدة 🧪</h1>
        <p style={s.sub}>بصفتك مدرس، يمكنك إضافة محتوى خاص بك أو ربطه بسكشن معين في كورساتك.</p>

        <form style={s.form}>
          <Field label="اربطها بسكشن من كورساتك (اختياري)" error={errors.section}>
            <select 
              name="section" 
              value={form.section} 
              onChange={handle} 
              style={s.select}
              disabled={fetchingCourses}
            >
              <option value="">-- تجربة عامة (غير مرتبطة بسكشن محدد) --</option>
              {myCourses.map(course => (
                <optgroup key={course.id} label={course.title}>
                  {course.sections?.map(sec => (
                    <option key={sec.id} value={sec.id}>
                      {course.title} › {sec.title}
                    </option>
                  ))}
                </optgroup>
              ))}
            </select>
            <p style={{fontSize: '0.75rem', color: '#888', marginTop: '5px'}}>
              {fetchingCourses ? 'جاري تحميل كورساتك...' : '* تظهر هنا السكاشن الخاصة بكورساتك فقط.'}
            </p>
          </Field>

          <Field label="عنوان التجربة" error={errors.title}>
            <input name="title" value={form.title} onChange={handle}
                   placeholder="مثال: مراجعة ليلة الامتحان لسكشن الـ OS" style={s.input} />
          </Field>

          <Field label="وصف المحتوى">
            <textarea name="description" value={form.description} onChange={handle}
                      placeholder="ما الذي سيحصل عليه الطالب عند شراء هذه التجربة؟" rows={4} style={{...s.input, resize:'vertical'}} />
          </Field>

          <div style={s.row}>
            <Field label="السعر (EGP)" error={errors.price} style={{ flex:1 }}>
              <input type="number" name="price" value={form.price}
                     onChange={handle} min="0" style={s.input} />
            </Field>
            <Field label="صورة الغلاف (Thumbnail)" style={{ flex:1 }}>
              <input type="file" name="image" onChange={handle} accept="image/*" style={s.input} />
            </Field>
          </div>

          <Field label="توزيع الأرباح %">
            <div style={s.splitWrap}>
              <div style={s.splitItem}>
                <label style={s.splitLabel}>حصتك كمدرس %</label>
                <input type="number" name="instructor_cut" value={form.instructor_cut}
                       onChange={handle} min="0" max="100" style={s.splitInput} />
              </div>
              <span style={s.splitPlus}>+</span>
              <div style={s.splitItem}>
                <label style={s.splitLabel}>حصة الكلية %</label>
                <input type="number" name="college_cut" value={form.college_cut}
                       readOnly style={{...s.splitInput, opacity:.6}} />
              </div>
              <span style={s.splitEq}>= 100%</span>
            </div>
          </Field>

          <div style={s.btnRow}>
            <button type="button" style={s.btnDraft}
                    onClick={(e) => submit(e, false)} disabled={loading}>
              {loading ? 'جاري الحفظ...' : '💾 حفظ كمسودة'}
            </button>
            <button type="button" style={s.btnPublish}
                    onClick={(e) => submit(e, true)} disabled={loading}>
              {loading ? 'جاري النشر...' : '🚀 نشر الآن'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

// ── Helper Components & Styles ──────────────────────────────────
function Field({ label, error, children, style }) {
  return (
    <div style={{ marginBottom: '1.25rem', ...style }}>
      <label style={fs.label}>{label}</label>
      {children}
      {error && <p style={fs.error}>{typeof error === 'string' ? error : Object.values(error).flat()[0]}</p>}
    </div>
  );
}

